var argv = require('optimist')
	.describe('group', 'Group to address')
	.default('group', 1)
	.alias('g', 'group')
	.describe('channel', 'Channel to address')
	.default('channel', 1)
	.alias('c', 'channel')
	.describe('output', 'Set outputs.')
	.alias('o', 'output')
	.describe('property', 'Property to address')
	.alias('p', 'property')
	.describe('device', 'Select device type.')
	.default('device', 'usb:CLASS_AN2056')
	.alias('d', 'device')
	.argv;

var vita = require('..');
var vita = vita.open(argv.device);

if ("output" in argv && !argv.property) {
	console.log("setOutputs");
	vita.setOutputs(argv.group, argv.channel, argv.output, function(err) {
		if (err) {
			console.log("\tError: " + err);
		} else {
			console.log('\tOutputs set to %s', argv.output.toString(10));
		}
	});
}

if ("property" in argv) {
	console.log("setProperty");
	vita.setProperty(argv.group, argv.channel, argv.property, argv.output, function(err) {
		if (err) {
			console.log("\tError: " + err);
		} else {
			console.log('\tProperty set to %s', argv.property.toString(10));
		}
	});
}
